// ---------- SAFE INPUT PARSER ----------

const input = $input.first();

// ✅ FIX: preserve binary
const binary = input.binary || {};

// Normalize browser codec MIME values (e.g. audio/webm;codecs=opus) to base types accepted by STT.
if (binary.audio?.mimeType && typeof binary.audio.mimeType === 'string') {
  const normalizedMime = binary.audio.mimeType.split(';')[0].trim().toLowerCase();
  binary.audio.mimeType = normalizedMime;
}

const body = input.json.body || input.json || {};

// ---------- METADATA ----------
const callerPhone = body.caller_phone || body.phone || 'unknown';
const callSid = body.call_sid || body.session_id || `call_${Date.now()}`;
const callType = body.call_type || 'inbound';

// ---------- CONVERSATION ----------
let conversationHistory = body.conversation_history || [];

if (typeof conversationHistory === 'string') {
  try {
    conversationHistory = JSON.parse(conversationHistory);
  } catch (e) {
    conversationHistory = [];
  }
}

if (!Array.isArray(conversationHistory)) {
  conversationHistory = [];
}

// ---------- INPUT TEXT ----------
let inputText = body.text || body.message || null;

if (!inputText && conversationHistory.length > 0) {
  const lastMsg = conversationHistory[conversationHistory.length - 1];
  if (lastMsg?.role === 'user') {
    inputText = lastMsg.content;
  }
}

// ---------- AUDIO DETECTION ----------
const hasBinaryAudio = !!binary.audio;

let audioBase64 = body.audio_base64 || null;
let audioUrl = body.audio_url || null;

const hasAudio = !!(audioBase64 || audioUrl || hasBinaryAudio);
const isTextOnly = !hasAudio && !!inputText;

// ---------- FIRST TURN ----------
const hasUserInput = !!inputText || hasAudio;
const hasHistory = conversationHistory.length > 0;

const isFirstTurn = !hasHistory && !hasUserInput;

// ---------- OUTPUT (CRITICAL FIX) ----------
return {
  json: {
    callerPhone,
    callSid,
    callType,

    conversationHistory,

    inputText,
    audioBase64,
    audioUrl,
    hasBinaryAudio,

    hasAudio,
    isTextOnly,
    isFirstTurn,

    timestamp: new Date().toISOString()
  },

  // 🔥 THIS IS THE FIX
  binary: binary
};

// Generate welcome message for first turn (no STT needed)
const callType = $('Parse Webhook Input').first().json.callType;
const callerPhone = $('Parse Webhook Input').first().json.callerPhone;

let welcomeText = '';
if (callType === 'outbound') {
  welcomeText = 'ஹலோ! நான் உங்கள் real estate assistant Kavya. நீங்கள் property enquiry form fill பண்ணிருந்தீங்க. என்ன மாதிரி property பார்க்கிறீங்க?';
} else {
  welcomeText = 'ஹலோ! நீங்கள் எங்கள் real estate team-க்கு call பண்ணிருக்கீங்க. Property details சொல்லலாம், site visit book பண்ணலாம். இப்போ என்ன help வேணும்?';
}

return {
  transcribedText: null,
  agentResponse: welcomeText,
  isFirstTurn: true,
  callerPhone,
  callSid: $('Parse Webhook Input').first().json.callSid,
  conversationHistory: [],
  skipSTT: true
};

// Prepare STT result and conversation context with robust transcript parsing
const sttResponse = $input.first().json;
const parsedInput = $('Parse Webhook Input').first().json;

const extractTranscript = (resp) => {
  if (!resp || typeof resp !== 'object') return '';
  if (typeof resp.transcript === 'string') return resp.transcript.trim();
  if (typeof resp.text === 'string') return resp.text.trim();
  if (typeof resp.output === 'string') return resp.output.trim();
  if (Array.isArray(resp.results)) {
    for (const item of resp.results) {
      if (typeof item?.transcript === 'string' && item.transcript.trim()) {
        return item.transcript.trim();
      }
    }
  }
  return '';
};

const transcribedText = extractTranscript(sttResponse);
const conversationHistory = Array.isArray(parsedInput.conversationHistory)
  ? [...parsedInput.conversationHistory]
  : [];

const sttFailed = transcribedText.length === 0;

// Add user message only when STT produced text
if (!sttFailed) {
  conversationHistory.push({
    role: 'user',
    content: transcribedText
  });
}

// Detect escalation keywords
const escalationKeywords = [
  'manager', 'human', 'person', 'urgent', 'complaint',
  'மேலாளர்', 'ஆள்', 'அவசரம்', 'problem'
];
const needsEscalation = !sttFailed && escalationKeywords.some((kw) =>
  transcribedText.toLowerCase().includes(kw.toLowerCase())
);

return [{
  json: {
    transcribedText,
    conversationHistory,
    callerPhone: parsedInput.callerPhone,
    callSid: parsedInput.callSid,
    needsEscalation,
    sttFailed,
    sttRaw: sttResponse,
    isFirstTurn: false
  }
}];

// Escalation path — notify human agent
const data = $input.first().json;

const escalationResponse = 'புரிந்தது. நான் இப்போது உங்களை எங்கள் human agent-கிட்ட transfer செய்கிறேன். சில நிமிடங்கள் hold-ல் இருங்கள்.';

// In production: trigger SMS/WhatsApp alert to human agent here
return [{
  json: {
    agentResponse: escalationResponse,
    transcribedText: data.transcribedText,
    conversationHistory: data.conversationHistory,
    callerPhone: data.callerPhone,
    callSid: data.callSid,
    isEscalated: true,
    escalationAlert: {
      phone: data.callerPhone,
      transcript: data.transcribedText,
      timestamp: new Date().toISOString()
    }
  }
}];

function safeGet(nodeName) {
  try {
    const data = $(nodeName).all();
    return data.length ? data[0].json : null;
  } catch (e) {
    return null;
  }
}

const escalationData = safeGet('🚨 Escalation Handler');
const llmData = safeGet('Message a model1');
const sttData = safeGet('📝 Process STT');
const welcomeData = safeGet('👋 Welcome Message');

let agentResponse = '';
let conversationHistory = sttData?.conversationHistory || welcomeData?.conversationHistory || [];
let callerPhone = sttData?.callerPhone || welcomeData?.callerPhone;
let callSid = sttData?.callSid || welcomeData?.callSid;
let isEscalated = false;
let isFirstTurn = welcomeData?.isFirstTurn || false;

if (isFirstTurn && welcomeData) {
  agentResponse = welcomeData.agentResponse;
} else if (sttData?.sttFailed) {
  agentResponse = 'மன்னிக்கவும், உங்கள் voice clear-ஆ கேட்கவில்லை. கொஞ்சம் மெதுவாக மறுபடியும் சொல்லுங்கள், அல்லது text-ஆ அனுப்பலாம்.';
  conversationHistory = [
    ...conversationHistory,
    { role: 'assistant', content: agentResponse }
  ];
} else if (escalationData?.isEscalated) {
  agentResponse = escalationData.agentResponse;
  isEscalated = true;
} else if (llmData) {
  const extractAssistantText = (data) => {
    if (typeof data?.text === 'string' && data.text.trim()) return data.text.trim();
    if (typeof data?.output === 'string' && data.output.trim()) return data.output.trim();

    const output0 = Array.isArray(data?.output) ? data.output[0] : null;
    const outContent0 = Array.isArray(output0?.content) ? output0.content[0] : null;
    if (typeof outContent0?.text === 'string' && outContent0.text.trim()) return outContent0.text.trim();

    const choiceText = data?.choices?.[0]?.message?.content;
    if (typeof choiceText === 'string' && choiceText.trim()) return choiceText.trim();

    const msgContent0 = Array.isArray(data?.content) ? data.content[0] : null;
    if (typeof msgContent0?.text === 'string' && msgContent0.text.trim()) return msgContent0.text.trim();

    return '';
  };

  agentResponse = extractAssistantText(llmData) || 'Sorry, clear-ah கேட்கல. இன்னொரு தடவை சொல்லுங்க.';

  // Unwrap accidental JSON-string responses like {"role":"assistant","content":"..."}
  const maybeJsonText = agentResponse.trim();
  if (maybeJsonText.startsWith('{') && maybeJsonText.endsWith('}')) {
    try {
      const parsed = JSON.parse(maybeJsonText);
      if (typeof parsed?.content === 'string' && parsed.content.trim()) {
        agentResponse = parsed.content.trim();
      }
    } catch (e) {
      // Keep original text when parsing fails
    }
  }

  // Keep spoken output simple, friendly Tamil/Tanglish (avoid very formal Tamil words).
  agentResponse = agentResponse
    .replaceAll('உதவட்டும்', 'help பண்ணலாம்')
    .replaceAll('உதவலாம்', 'help பண்ணலாம்')
    .replaceAll('அவசியம்', 'தேவைனா')
    .replaceAll('தொடரவும்', 'continue பண்ணலாம்')
    .replaceAll('வணக்கம்', 'ஹலோ');

  conversationHistory = [
    ...conversationHistory,
    { role: 'assistant', content: agentResponse }
  ];
} else {
  agentResponse = 'மன்னிக்கவும், response generate ஆகவில்லை. மீண்டும் முயற்சி செய்யுங்கள்.';
}

return [{
  json: {
    agentResponse,
    conversationHistory,
    callerPhone,
    callSid,
    isEscalated,
    transcribedText: sttData?.transcribedText || null,
    sttFailed: sttData?.sttFailed || false,
    sttRaw: sttData?.sttRaw || null
  }
}];

// Prepare final response payload
const ttsData = $('Post to Sarvam TTS').first().json;
const mergeData = $('Merge Response Streams').first().json;

// TTS returns base64 audio chunks
const audioChunks = ttsData.audios || [];
const audioBase64 = audioChunks[0] || '';

return {
  json: {
    success: true,
    call_sid: mergeData.callSid,
    caller_phone: mergeData.callerPhone,
    transcribed_text: mergeData.transcribedText,
    stt_failed: mergeData.sttFailed || false,
    agent_response_text: mergeData.agentResponse,
    audio_base64: audioBase64,
    audio_format: 'wav',
    sample_rate: 8000,
    is_escalated: mergeData.isEscalated,
    conversation_history: mergeData.conversationHistory,
    continue_conversation: !mergeData.isEscalated,
    timestamp: new Date().toISOString()
  }
};

const input = $input.first().json;

const history = Array.isArray(input.conversationHistory) ? input.conversationHistory : [];
const latestUserText = typeof input.transcribedText === 'string' ? input.transcribedText.trim() : '';

const isLikelyName = (text) => {
  if (!text) return false;
  const words = text.split(/\s+/).filter(Boolean);
  if (words.length === 0 || words.length > 3) return false;
  if (/\d/.test(text)) return false;
  return text.length >= 2 && text.length <= 30;
};

const askedNameRecently = history
  .slice(-4)
  .some((msg) => msg?.role === 'assistant' && typeof msg?.content === 'string' && msg.content.includes('பெயர்'));

const callerName = askedNameRecently && isLikelyName(latestUserText) ? latestUserText : '';

const numberMatch = latestUserText.match(/(?:\+?\d[\d\s\-]{7,}\d)/);
const extractedCallerNumber = numberMatch ? numberMatch[0].replace(/\s+/g, ' ').trim() : '';

const intentKeywords = [
  { key: 'site_visit', words: ['நேரில்', 'visit', 'பார்க்க'] },
  { key: 'pricing', words: ['விலை', 'price', 'லட்சம்', 'கோடி'] },
  { key: 'location', words: ['area', 'ஏரியா', 'omr', 'porur', 'அண்ணா நகர்', 'போரூர்'] },
  { key: 'callback', words: ['call', 'phone', 'தொலைபேசி'] }
];

let callerIntent = 'general_query';
const lowerText = latestUserText.toLowerCase();
for (const intent of intentKeywords) {
  if (intent.words.some((w) => lowerText.includes(w.toLowerCase()))) {
    callerIntent = intent.key;
    break;
  }
}

return [{
  json: {
    timestamp: new Date().toISOString(),
    call_sid: input.callSid || '',
    caller_id: input.callerPhone || '',
    caller_phone: input.callerPhone || '',
    caller_name: callerName,
    caller_intent: callerIntent,
    extracted_caller_number: extractedCallerNumber,
    user_last_message: latestUserText,
    agent_last_reply: input.agentResponse || '',
    stt_failed: Boolean(input.sttFailed),
    is_escalated: Boolean(input.isEscalated),
    continue_conversation: !Boolean(input.isEscalated),
    audio_format: '',
    sample_rate: '',
    history_length: history.length
  }
}];
